909: function getGridHeight(height: number | string) {
910:   if (isString(height)) {
911:     height = parseInt(height.replace('px', ''), 10);
912:   }
913: 
914:   if (height < MIN_PANEL_HEIGHT) {
915:     height = MIN_PANEL_HEIGHT;
916:   }
